async function main() {
  console.log(`Processing ${updates.length} products...`);
  let success = 0;
  let fail = 0;

  for (const u of updates) {
    try {
      const wordCount = u.description.trim().split(/\s+/).length;
      const metaLen = u.metaDescription.length;
      console.log(`  [${u.slug}] Words: ${wordCount}, Meta chars: ${metaLen}`);

      if (wordCount < 250) {
        console.log(`    ⚠️  WARNING: Description is under 250 words (${wordCount})`);
      }
      if (metaLen < 130 || metaLen > 155) {
        console.log(`    ⚠️  WARNING: Meta description length ${metaLen} outside 130-155 range`);
      }

      await prisma.product.update({
        where: { slug: u.slug },
        data: {
          description: u.description,
          metaDescription: u.metaDescription,
        },
      });
      console.log(`    ✓ Updated`);
      success++;
    } catch (err) {
      console.log(`    ✗ Failed: ${err.message}`);
      fail++;
    }
  }

  console.log(`\nDone. ${success} succeeded, ${fail} failed out of ${updates.length} products.`);
  await prisma.$disconnect();
}

main();
